use std::collections::HashMap;

#[derive(Debug, Clone)]
struct Tile {
    x: i32,
    y: i32,
    is_solid: bool,
}

fn process_game_map(tiles: &mut Vec<Tile>) -> Vec<(i32, i32)> {
    let filtered_and_mapped: Vec<(i32, i32)> = tiles.iter()
        .filter(|tile| tile.is_solid)
        .map(|tile| (tile.x + 2, tile.y))
        .collect();

    for entity in filtered_and_mapped.iter() {
        if let Some(original_tile) = tiles.iter_mut().find(|t| t.is_solid && t.x == entity.0 - 2 && t.y == entity.1)
        {
            original_tile.x = entity.0;
        }
    }

    filtered_and_mapped
}

use std::collections::HashMap;

struct LogEntry {
    date: String,
    message: String,
}

fn analyze_logs(entries: Vec<LogEntry>) -> HashMap<String, i32> {
    let processed_counts = entries.into_iter()
        .filter(|entry| !entry.message.is_empty())
        .map(|entry| { 
            let parts: Vec<&str> = entry.message.split_whitespace().collect();
            if let (Some(count_str), Some(_)) = (parts.get(0), parts.get(1)) {
                (entry.date.clone(), count_str.parse::<i32>().unwrap_or(0))
            } else {
                (String::new(), 0)
            }
        })
        .collect::<Vec<(String, i32)>>();

    let mut daily_totals: HashMap<String, i32> = HashMap::new();
    for (date, count) in processed_counts {
        *daily_totals.entry(date).or_insert(0) += count;
    }
    daily_totals
}

use std::collections::HashMap;

struct HttpRequest {
    path: String,
    headers: HashMap<String, String>,
}

fn process_requests(requests: Vec<HttpRequest>) -> Vec<HashMap<String, String>> {
    let filtered_and_mapped = requests
        .into_iter()
        .filter(|req| !req.path.is_empty())
        .map(|req| {
            let mut new_headers = HashMap::new();
            for (key, value) in req.headers.iter() {
                if key == "Host" {
                    new_headers.insert("X-Real-Host".to_string(), value.clone());
                } else {
                    new_headers.insert(key.clone(), value.clone());
                }
            }
            new_headers
        });

    filtered_and_mapped.collect()
}

use std::collections::HashSet;

struct Coord { 
    x: i32,
    y: i32
}

fn is_in_bounds(coords: &Coord, max_x: i32, max_y: i32) -> bool {
    coords.x >= 0 && coords.x < max_x && coords.y >= 0 && coords.y < max_y
}

fn process_cell_data(initial_coords: Vec<Coord>, map_width: i32, map_height: i32) -> Vec<(i32, i32)> {
    let filtered = initial_coords.into_iter()
        .filter(|c| is_in_bounds(c, map_width, map_height))
        .collect::<Vec<Coord>>();

    let mapped: Vec<(i32, i32)> = filtered.into_iter()
        .map(|c| (c.x * 2, c.y))
        .collect();

    mapped
}

