struct UploadRecord {
    filename: String,
    size_bytes: usize,
    is_valid: bool,
}

fn process_uploads(raw_data: Vec<String>) -> Vec<UploadRecord> {
    let initial_records = raw_data.into_iter().map(|s| {
        let parts: Vec<&str> = s.split(':').collect();
        if parts.len() == 2 {
            let filename = parts[0].to_string();
            let size = parts[1].parse::<usize>().unwrap_or(0);
            UploadRecord { 
                filename, 
                size_bytes: size,
                is_valid: true
            }
        } else {
            UploadRecord { 
                filename: "unknown".to_string(), 
                size_bytes: 0,
                is_valid: false
            }
        }
    }).collect::<Vec<UploadRecord>>();

    let filtered_records: Vec<UploadRecord> = initial_records.into_iter()
        .filter(|record| record.size_bytes > 100)
        .map(|mut record| {
            if record.filename.contains(".exe") {
                record.is_valid = false;
            } else {
                // Simulate successful processing/mapping
                record.is_valid = true;
            }
            record
        })
        .collect();

    filtered_records
}
